describe('shortenPseudonym', () => {
  beforeEach(() => {
    vi.stubGlobal('base64js', base64js);
  });

  afterEach(() => {
    vi.restoreAllMocks();
    vi.unstubAllGlobals();
  });

  // --- Happy Path ---

  it('should return first N characters of a pseudonym string', () => {
    const result = shortenPseudonym(SAMPLE_PSEUDONYM, 8);

    expect(typeof result).toBe('string');
    expect(result).toHaveLength(8);
    expect(result).toBe(SAMPLE_PSEUDONYM.substring(0, 8));
    expect(SAMPLE_PSEUDONYM.startsWith(result)).toBe(true);
  });

  it('should default to length 8 when length is omitted', () => {
    const result = shortenPseudonym(SAMPLE_PSEUDONYM);

    expect(result).toHaveLength(8);
    expect(result).toBe(SAMPLE_PSEUDONYM.substring(0, 8));
  });

  // --- Boundary / Edge Cases ---

  it('should return empty string when length is 0', () => {
    const result = shortenPseudonym(SAMPLE_PSEUDONYM, 0);
    expect(result).toBe('');
  });

  it('should return empty string when length is negative', () => {
    const result = shortenPseudonym(SAMPLE_PSEUDONYM, -5);
    expect(result).toBe('');
  });

  it('should return single character when length is 1', () => {
    const result = shortenPseudonym(SAMPLE_PSEUDONYM, 1);
    expect(result).toHaveLength(1);
    expect(result).toBe(SAMPLE_PSEUDONYM[0]);
  });

  it('should return the full string when length equals the string length', () => {
    const result = shortenPseudonym(SAMPLE_PSEUDONYM, SAMPLE_PSEUDONYM.length);
    expect(result).toBe(SAMPLE_PSEUDONYM);
  });

  it('should return the full string when length exceeds string length (clamped)', () => {
    const result = shortenPseudonym(SAMPLE_PSEUDONYM, 1000);
    expect(result).toBe(SAMPLE_PSEUDONYM);
  });

  it('should return empty string when input pseudonym is empty', () => {
    const result = shortenPseudonym('', 8);
    expect(result).toBe('');
  });

  // --- Input Validation ---

  it('should throw missing_pseudonym when pseudonymBase64 is undefined', () => {
    expect(() =>
      shortenPseudonym(undefined as unknown as string)
    ).toThrow(/missing_pseudonym/);
  });

  it('should throw missing_pseudonym when pseudonymBase64 is null', () => {
    expect(() =>
      shortenPseudonym(null as unknown as string)
    ).toThrow(/missing_pseudonym/);
  });

  it('should throw invalid_pseudonym_type when pseudonymBase64 is not a string', () => {
    expect(() =>
      shortenPseudonym(12345 as unknown as string)
    ).toThrow(/invalid_pseudonym_type/);
  });

  it('should throw invalid_length_type when length is not a number', () => {
    expect(() =>
      shortenPseudonym('abc', 'not-a-number' as unknown as number)
    ).toThrow(/invalid_length_type/);
  });

  it('should throw invalid_length_type when length is a float (not integer)', () => {
    expect(() =>
      shortenPseudonym('abc', 3.5)
    ).toThrow(/invalid_length_type/);
  });

  // --- Synchronous Return ---

  it('should return a plain string synchronously, not a Promise', () => {
    const result = shortenPseudonym(SAMPLE_PSEUDONYM, 8);

    expect(typeof result).toBe('string');
    // Ensure it's not a Promise (duck-type check)
    expect(result).not.toBeInstanceOf(Promise);
    expect((result as any).then).toBeUndefined();
  });
});

